#include <vector>
#include <map>
#include <set>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    class DSU {
        vector<int> parent;
    public:
        DSU(int n) : parent(n + 1) {
            for (int i = 0; i <= n; ++i) parent[i] = i;
        }
        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }
        void unite(int x, int y) {
            int root_x = find(x);
            int root_y = find(y);
            if (root_x != root_y) {
                parent[root_y] = root_x;
            }
        }
    };

    DSU dsu(c);
    for (const auto& conn : connections) {
        int u = conn[0];
        int v = conn[1];
        dsu.unite(u, v);
    }

    map<int, multiset<int>> component_multisets;
    for (int i = 1; i <= c; ++i) {
        int root = dsu.find(i);
        component_multisets[root].insert(i);
    }

    vector<bool> online(c + 1, true);
    vector<long long> result;

    for (const auto& q : queries) {
        int type = q[0];
        int x = q[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                int root = dsu.find(x);
                auto& s = component_multisets[root];
                if (s.empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*s.begin());
                }
            }
        } else {
            online[x] = false;
            int root = dsu.find(x);
            auto& s = component_multisets[root];
            s.erase(x);
        }
    }

    return result;
}

