use std::collections::{BTreeSet, HashMap};

struct DSU {
    parent: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        let mut parent = vec![0; n + 1];
        for i in 1..=n {
            parent[i] = i;
        }
        DSU { parent }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            self.parent[root_y] = root_x;
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut dsu = DSU::new(c);
    for conn in &connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        dsu.union(u, v);
    }

    let mut component_map = HashMap::new();
    for i in 1..=c {
        let root = dsu.find(i);
        let entry = component_map.entry(root).or_insert_with(BTreeSet::new);
        entry.insert(i);
    }

    let mut online = vec![true; c + 1];
    let mut result = Vec::new();

    for q in queries {
        let type_q = q[0];
        let x = q[1] as usize;
        if type_q == 1 {
            if online[x] {
                result.push(x as i64);
            } else {
                let root = dsu.find(x);
                if component_map.get(&root).unwrap().is_empty() {
                    result.push(-1);
                } else {
                    let min = component_map.get_mut(&root).unwrap().range().next().unwrap();
                    result.push(*min as i64);
                }
            }
        } else {
            online[x] = false;
            let root = dsu.find(x);
            if let Some(s) = component_map.get_mut(&root) {
                s.remove(&x);
            }
        }
    }

    result
}
