use std::collections::{HashMap, BTreeSet};

struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        let parent = (0..=n).map(|i| i).collect();
        let rank = vec![1; n + 1];
        DSU { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn unite(&mut self, x: usize, y: usize) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            if self.rank[root_x] < self.rank[root_y] {
                self.parent[root_x] = root_y;
            } else {
                self.parent[root_y] = root_x;
                if self.rank[root_x] == self.rank[root_y] {
                    self.rank[root_x] += 1;
                }
            }
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut dsu = DSU::new(c);
    for conn in &connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        dsu.unite(u, v);
    }

    let mut component_sets = HashMap::new();
    for i in 1..=c {
        let root = dsu.find(i);
        component_sets.entry(root).or_insert_with(BTreeSet::new).insert(i);
    }

    let mut online = vec![true; c + 1]; // 1-based index
    let mut result = Vec::new();

    for q in queries {
        let type_q = q[0];
        let x = q[1] as usize;
        if type_q == 1 {
            if online[x] {
                result.push(x as i64);
            } else {
                let root = dsu.find(x);
                if let Some(s) = component_sets.get(&root) {
                    if s.is_empty() {
                        result.push(-1);
                    } else {
                        let min = *s.iter().next().unwrap();
                        result.push(min as i64);
                    }
                } else {
                    result.push(-1);
                }
            }
        } else {
            online[x] = false;
            let root = dsu.find(x);
            if let Some(s) = component_sets.get_mut(&root) {
                s.remove(&x);
            }
        }
    }

    result
}
