        DSU(int n) : parent(n + 1) {
            for (int i = 0; i <= n; ++i) parent[i] = i;
        }
        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }
