                int root = dsu.find(x);
                auto& s = component_multisets[root];
                if (s.empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*s.begin());
                }
            }
        } else {
            online[x] = false;
            int root = dsu.find(x);
            auto& s = component_multisets[root];
            s.erase(x);
        }
    }

    return result;
}
